  std::vector<Enrollment> enrollments;
  auto write_enrollments_result = sqlgen::write(conn, enrollments);
  if (!write_enrollments_result) {
    throw std::runtime_error("Failed to create Enrollment table");
  }

  // 3. Perform the query using read function with left join and group by
  auto result = sqlgen::read<std::vector<CourseStatsView>>(
      sqlgen::select_from<Course>("title"_c) |
      sqlgen::left_join<Enrollment>("course_id"_c == "course_id"_c) |
      sqlgen::group_by("course_id"_c, "title"_c) |
