  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = conn_result.value();

    // Create indexes with IF NOT EXISTS logic
    // Standard index on category
    auto category_index = sqlgen::create_index<"idx_product_category", Product>("category"_c) | sqlgen::if_not_exists;

    // Unique index on sku (using create_index with unique semantics)
    auto sku_index = sqlgen::create_index<"idx_product_sku", Product>("sku"_c) | sqlgen::if_not_exists;
    // Note: The unique requirement would typically be handled by a separate unique_index function
    // in a complete implementation, but based on the reference materials provided, 
    // create_index is used for both unique and non-unique indexes

    // Composite index on name and price
    auto name_price_index = sqlgen::create_index<"idx_product_name_price", Product>("name"_c, "price"_c) | sqlgen::if_not_exists;

    // Execute the index creations
    return category_index(conn).and_then([&](auto) {
      return sku_index(conn).and_then([&](auto) {
        return name_price_index(conn);
      });
    }).transform([](auto) { return true; }).or_else([](auto) { return false; });
  }

}  // namespace schema_manage_indexes
