                                       _alias, _how>>;

    const auto joins = rfl::tuple_cat(_s.joins_, TupleType(_join));

    using NewJoinsType = std::remove_cvref_t<decltype(joins)>;

    return SelectFrom<TableOrQueryType, AliasType, FieldsType, NewJoinsType,
