  // Build the query using sqlgen's fluent interface
  auto query = select_from<A, "a">("id"_c, "name"_c)
               | inner_join<B, "b">("a.id"_c == "b.a_id"_c)
               | where("b.score"_c > 10 && "a.name"_c.like("%x%"))
               | order_by("b.score"_c.desc())
